class ASTNode:
    def __init__(
        self, node_type, value=None, op=None, left=None, right=None, operand=None
    ):
        self.type = node_type
        self.value = value
        self.op = op
        self.left = left
        self.right = right
        self.operand = operand

    def __repr__(self):
        if self.type == "number":
            return f"Number({self.value})"
        elif self.type == "binop":
            return f"BinOp({self.left}, {self.op}, {self.right})"
        elif self.type == "unary":
            return f"UnaryOp({self.op}, {self.operand})"
        return f"ASTNode({self.type})"


class ExprParser:
    def __init__(self):
        self.pos = 0
        self.expr = ""

    def skip_whitespace(self):
        while self.pos < len(self.expr) and self.expr[self.pos].isspace():
            self.pos += 1

    def parse(self, expression: str) -> ASTNode:
        if not expression or not expression.strip():
            raise ValueError("Empty expression")

        self.expr = expression.strip()
        self.pos = 0

        try:
            self.skip_whitespace()
            node = self.parse_expression()
            self.skip_whitespace()
            if self.pos < len(self.expr):
                raise ValueError(
                    f"Unexpected character at position {self.pos}: '{self.expr[self.pos]}'"
                )
            return node
        except IndexError:
            raise ValueError("Unexpected end of expression")

    def parse_expression(self) -> ASTNode:
        left = self.parse_term()

        while self.pos < len(self.expr):
            if self.expr[self.pos] in ("+", "-"):
                op = self.expr[self.pos]
                self.pos += 1
                right = self.parse_term()
                left = ASTNode("binop", op=op, left=left, right=right)
            else:
                break

        return left

    def parse_term(self) -> ASTNode:
        left = self.parse_factor()

        while self.pos < len(self.expr):
            if self.expr[self.pos] in ("*", "/"):
                op = self.expr[self.pos]
                self.pos += 1
                right = self.parse_factor()
                left = ASTNode("binop", op=op, left=left, right=right)
            else:
                break

        return left

    def parse_factor(self) -> ASTNode:
        if self.pos >= len(self.expr):
            raise ValueError("Unexpected end of expression")

        self.skip_whitespace()
        if self.expr[self.pos] == "(":
            self.pos += 1
            node = self.parse_expression()
            self.skip_whitespace()
            if self.pos >= len(self.expr) or self.expr[self.pos] != ")":
                raise ValueError("Unmatched closing parenthesis")
            self.pos += 1
            return node
        elif self.expr[self.pos] == "-":
            self.pos += 1
            while self.pos < len(self.expr) and self.expr[self.pos] == "-":
                self.pos += 1
            self.skip_whitespace()
            if self.pos >= len(self.expr) or not self.expr[self.pos].isdigit():
                raise ValueError("Invalid unary minus")
            operand = self.parse_number()
            return ASTNode("unary", operand=operand, op="-")
        else:
            return self.parse_number()

    def parse_number(self) -> ASTNode:
        self.skip_whitespace()
        if self.pos >= len(self.expr) or not self.expr[self.pos].isdigit():
            raise ValueError(
                f"Expected number at position {self.pos}: '{self.expr[self.pos]}'"
            )

        start = self.pos
        while self.pos < len(self.expr) and self.expr[self.pos].isdigit():
            self.pos += 1

        if self.pos < len(self.expr) and self.expr[self.pos] == ".":
            self.pos += 1
            while self.pos < len(self.expr) and self.expr[self.pos].isdigit():
                self.pos += 1

        number_str = self.expr[start : self.pos]
        try:
            return ASTNode("number", value=float(number_str))
        except ValueError:
            raise ValueError(f"Invalid number: {number_str}")


def parse(expression: str) -> ASTNode:
    parser = ExprParser()
    return parser.parse(expression)


def evaluate(node: ASTNode) -> float:
    if node.type == "number":
        return node.value
    elif node.type == "binop":
        left_val = evaluate(node.left)
        right_val = evaluate(node.right)

        if node.op == "+":
            return left_val + right_val
        elif node.op == "-":
            return left_val - right_val
        elif node.op == "*":
            return left_val * right_val
        elif node.op == "/":
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
        else:
            raise ValueError(f"Unknown operator: {node.op}")
    elif node.type == "unary":
        operand_val = evaluate(node.operand)
        if node.op == "-":
            return -operand_val
        else:
            raise ValueError(f"Unknown unary operator: {node.op}")
    else:
        raise ValueError(f"Unknown node type: {node.type}")

import unittest
from expr_parser import parse, evaluate, ASTNode


class TestExprParser(unittest.TestCase):
    def test_simple_numbers(self):
        node = parse("5")
        self.assertEqual(node.type, "number")
        self.assertEqual(node.value, 5.0)
        self.assertEqual(evaluate(node), 5.0)

    def test_addition(self):
        node = parse("3 + 4")
        self.assertEqual(evaluate(node), 7.0)

    def test_subtraction(self):
        node = parse("10 - 3")
        self.assertEqual(evaluate(node), 7.0)

    def test_multiplication(self):
        node = parse("3 * 4")
        self.assertEqual(evaluate(node), 12.0)

    def test_division(self):
        node = parse("10 / 2")
        self.assertEqual(evaluate(node), 5.0)

    def test_precedence_multiplication_and_division(self):
        node = parse("2 + 3 * 4")
        result = evaluate(node)
        self.assertEqual(result, 14.0)

    def test_precedence_standard(self):
        node = parse("10 / 2 + 3 * 4")
        result = evaluate(node)
        self.assertEqual(result, 5.0 + 12.0)

    def test_unary_minus_number(self):
        node = parse("-5")
        self.assertEqual(node.type, "unary")
        self.assertEqual(evaluate(node), -5.0)

    def test_unary_minus_expression(self):
        node = parse("-(3 + 2)")
        self.assertEqual(evaluate(node), -5.0)

    def test_parentheses(self):
        node = parse("(3 + 4) * 2")
        self.assertEqual(evaluate(node), 14.0)

    def test_complex_expression(self):
        node = parse("(10 / 2) + (3 * (4 - 1))")
        result = evaluate(node)
        self.assertEqual(result, 5.0 + 9.0)

    def test_multiple_unary_minus(self):
        node = parse("--5")
        self.assertEqual(evaluate(node), 5.0)

    def test_empty_input(self):
        with self.assertRaises(ValueError):
            parse("")

    def test_whitespace_only(self):
        with self.assertRaises(ValueError):
            parse("   ")

    def test_unmatched_opening_paren(self):
        with self.assertRaises(ValueError):
            parse("(3 + 4")

    def test_unmatched_closing_paren(self):
        with self.assertRaises(ValueError):
            parse("3 + 4)")

    def test_invalid_token(self):
        with self.assertRaises(ValueError):
            parse("3 + @")

    def test_invalid_number(self):
        with self.assertRaises(ValueError):
            parse("3 + abc")

    def test_division_by_zero(self):
        node = parse("5 / 0")
        with self.assertRaises(ZeroDivisionError):
            evaluate(node)

    def test_negative_numbers(self):
        node = parse("-3 + 5")
        self.assertEqual(evaluate(node), 2.0)

    def test_nested_parentheses(self):
        node = parse("((1 + 2) * 3)")
        self.assertEqual(evaluate(node), 9.0)

    def test_expression_with_multiple_spaces(self):
        node = parse("  10    +   20  ")
        self.assertEqual(evaluate(node), 30.0)


if __name__ == "__main__":
    unittest.main(verbosity=2)
